const now = new Date();

// Converte para string no timezone de São Paulo e depois recria a data
const brasiliaDateString = now.toLocaleString('en-US', { 
  timeZone: 'America/Sao_Paulo',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
});

// Parse da data no formato MM/DD/YYYY para criar objeto Date "limpo"
