yesterday.setDate(yesterday.getDate() - 1);

// Formata para YYYY-MM-DD
const yearStr = yesterday.getFullYear();
const monthStr = String(yesterday.getMonth() + 1).padStart(2, '0');
const dayStr = String(yesterday.getDate()).padStart(2, '0');
const dateStr = `${yearStr}-${monthStr}-${dayStr}`;

// --- Campos que você quer puxar ---
const fields = [
  "campaign_name",
  "adset_name",
  "impressions",
  "clicks",
  "spend",
  "actions",
  "action_values",
  "cpc",
  "cpm",
  "ctr",
  "reach",
  "frequency",
  "date_start"
].join(',');

// --- Monta o time_range codificado ---
const timeRange = encodeURIComponent(JSON.stringify({ 
  since: dateStr, 
  until: dateStr 
}));

