  // Limite de resultados por request
  limit: 500
};

// ========== FUNÇÃO PARA PEGAR DATA NO TIMEZONE BRASIL ==========
function getDateBrasilia(daysOffset = 0) {
  const now = new Date();
  const brasiliaDateString = now.toLocaleString('en-US', { 
    timeZone: 'America/Sao_Paulo',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  });

  const [month, day, year] = brasiliaDateString.split('/');
  const todayBrasilia = new Date(year, month - 1, day);

  // Aplica offset de dias
  todayBrasilia.setDate(todayBrasilia.getDate() + daysOffset);

  // Formata para YYYY-MM-DD
  const yearStr = todayBrasilia.getFullYear();
  const monthStr = String(todayBrasilia.getMonth() + 1).padStart(2, '0');
  const dayStr = String(todayBrasilia.getDate()).padStart(2, '0');

  return `${yearStr}-${monthStr}-${dayStr}`;
}

// ========== GERA ARRAY DE DATAS ==========
const items = [];
const fieldsParam = CONFIG.fields.join(',');

// Loop pelos últimos N dias (incluindo ontem)
for (let i = 1; i <= CONFIG.diasHistorico; i++) {
  const dateStr = getDateBrasilia(-i); // -1 = ontem, -2 = anteontem, etc

  const timeRange = encodeURIComponent(JSON.stringify({ 
    since: dateStr, 
    until: dateStr 
  }));

  // Gera um item por ACT para este dia
  CONFIG.acts.forEach(act => {
    items.push({
      json: {
        act_id: act,
        since: dateStr,
        until: dateStr,
        url: `https://graph.facebook.com/${CONFIG.apiVersion}/${act}/insights?fields=${encodeURIComponent(fieldsParam)}&time_range=${timeRange}&limit=${CONFIG.limit}`
      }
    });
  });
}

return items;

